def get_player_highlights(player_name):
    player_data = {
        "Dwayne L. Polee Sr.": [
            "1981 Los Angeles City Section Player of the Year",
            "Scored 43 points in the 1981 City championship game (82-69 win over Crenshaw High School)",
            "Drafted by the Los Angeles Clippers in the 1986 NBA draft",
            "Played 1 game in the NBA during the 1986–87 season",
            "Played professionally in Mexico with Limoneros de Colima (1989–1991)",
            "Director of Player Development at the University of San Francisco (since 2012)"
        ],
        "Dwayne Polee Jr.": [
            "2010 Los Angeles City Section Player of the Year",
            "Played college basketball for San Diego State"
        ]
    }
    return player_data.get(player_name, "Player not found in records.")

# Example usage:
print(get_player_highlights("Dwayne L. Polee Sr."))
